SELECT /* base.ec.pd :: PdProdBundleItem :: selectList */ i.* , ste.site_nm AS site_nm , prd.prod_nm AS bundle_prod_nm , prd2.prod_nm AS item_prod_nm FROM pd_prod_bundle_item i LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN pd_prod prd ON prd.prod_id = i.bundle_prod_id LEFT JOIN pd_prod prd2 ON prd2.prod_id = i.item_prod_id
ORDER BY i.bundle_item_id ASC ORDER BY i.bundle_item_id DESC ORDER BY i.reg_date ASC ORDER BY i.reg_date DESC ORDER BY i.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

